function solve(c, connections, queries) {
    class DSU {
        constructor(size) {
            this.parent = Array(size + 1).fill(0).map((_, i) => i);
            this.rank = Array(size + 1).fill(0);
        }
        find(x) {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }
        union(x, y) {
            const xRoot = this.find(x);
            const yRoot = this.find(y);
            if (xRoot === yRoot) return;
            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
        }
    }

    class MinHeap {
        constructor() {
            this.heap = [];
        }
        push(value) {
            this.heap.push(value);
            this.siftUp(this.heap.length - 1);
        }
        siftUp(index) {
            while (index > 0) {
                const parent = (index - 1) >> 1;
                if (this.heap[parent] <= this.heap[index]) {
                    break;
                }
                [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
                index = parent;
            }
        }
        pop() {
            if (this.heap.length === 0) return null;
            const value = this.heap[0];
            this.heap[0] = this.heap[this.heap.length - 1];
            this.heap.pop();
            this.siftDown(0);
            return value;
        }
        siftDown(index) {
            while (true) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < this.heap.length && this.heap[left] < this.heap[smallest]) {
                    smallest = left;
                }
                if (right < this.heap.length && this.heap[right] < this.heap[smallest]) {
                    smallest = right;
                }
                if (smallest === index) break;
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                index = smallest;
            }
        }
        peek() {
            return this.heap[0];
        }
    }

    const dsu = new DSU(c);
    for (const [u, v] of connections) {
        dsu.union(u, v);
    }

    const components = new Map();
    for (let i = 1; i <= c; i++) {
        const root = dsu.find(i);
        if (!components.has(root)) {
            components.set(root, []);
        }
        components.get(root).push(i);
    }

    const componentHeaps = new Map();
    for (const [root, stations] of components.entries()) {
        const heap = new MinHeap();
        for (const station of stations) {
            heap.push(station);
        }
        componentHeaps.set(root, heap);
    }

    const online = new Array(c + 1).fill(true);

    const result = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = dsu.find(x);
                const heap = componentHeaps.get(root);
                let currentTop;
                while (true) {
                    currentTop = heap.peek();
                    if (currentTop === undefined) {
                        result.push(-1);
                        break;
                    }
                    if (online[currentTop]) {
                        result.push(currentTop);
                        break;
                    } else {
                        heap.pop();
                    }
                }
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}

