#include <vector>
#include <map>
#include <priority_queue>
#include <algorithm>

using namespace std;

class DSU {
public:
    DSU(long long size) {
        parent.resize(size + 1);
        rank.resize(size + 1);
        for (long long i = 0; i <= size; i++) {
            parent[i] = i;
            rank[i] = 0;
        }
    }

    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void union_(long long x, long long y) {
        long long xRoot = find(x);
        long long yRoot = find(y);
        if (xRoot == yRoot) return;
        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot;
        } else {
            parent[yRoot] = xRoot;
            if (rank[xRoot] == rank[yRoot]) {
                rank[xRoot]++;
            }
        }
    }

private:
    vector<long long> parent;
    vector<long long> rank;
};

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    DSU dsu(c);
    for (auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        dsu.union_(u, v);
    }

    map<long long, priority_queue<long long, vector<long long>, greater<long long>>> componentHeaps;

    for (long long i = 1; i <= c; i++) {
        long long root = dsu.find(i);
        if (componentHeaps.find(root) == componentHeaps.end()) {
            componentHeaps[root] = priority_queue<long long, vector<long long>, greater<long long>>();
        }
        componentHeaps[root].push(i);
    }

    vector<bool> online(c + 1, true);

    vector<long long> result;

    for (auto& q : queries) {
        long long type = q[0];
        long long x = q[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                long long root = dsu.find(x);
                auto& heap = componentHeaps[root];
                while (!heap.empty()) {
                    long long current = heap.top();
                    if (online[current]) {
                        result.push_back(current);
                        break;
                    } else {
                        heap.pop();
                    }
                }
                if (heap.empty()) {
                    result.push_back(-1);
                }
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}
