#include <vector>
#include <map>
#include <priority_queue>
#include <algorithm>

using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    class DSU {
    public:
        vector<long long> parent;
        vector<long long> rank;
        DSU(long long size) {
            parent.resize(size + 1);
            rank.resize(size + 1);
            for (long long i = 0; i <= size; ++i) {
                parent[i] = i;
                rank[i] = 0;
            }
        }
        long long find(long long x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }
        void union_(long long x, long long y) {
            long long xRoot = find(x);
            long long yRoot = find(y);
            if (xRoot == yRoot) return;
            if (rank[xRoot] < rank[yRoot]) {
                parent[xRoot] = yRoot;
            } else {
                parent[yRoot] = xRoot;
                if (rank[xRoot] == rank[yRoot]) {
                    rank[xRoot]++;
                }
            }
        }
    };

    DSU dsu(c);
    for (auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        dsu.union_(u, v);
    }

    map<long long, vector<long long>> components;
    for (long long i = 1; i <= c; ++i) {
        long long root = dsu.find(i);
        if (components.find(root) == components.end()) {
            components[root] = vector<long long>();
        }
        components[root].push_back(i);
    }

    map<long long, priority_queue<long long, vector<long long>, greater<long long>>> componentHeaps;
    for (auto& [root, stations] : components) {
        priority_queue<long long, vector<long long>, greater<long long>> heap;
        for (long long station : stations) {
            heap.push(station);
        }
        componentHeaps[root] = heap;
    }

    vector<bool> online(c + 1, true);

    vector<long long> result;
    for (auto& query : queries) {
        long long type = query[0];
        long long x = query[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                long long root = dsu.find(x);
                priority_queue<long long, vector<long long>, greater<long long>>& heap = componentHeaps[root];
                while (true) {
                    if (heap.empty()) {
                        result.push_back(-1);
                        break;
                    }
                    long long top = heap.top();
                    if (online[top]) {
                        result.push_back(top);
                        break;
                    } else {
                        heap.pop();
                    }
                }
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}
