class MinHeap {
    vector<long long> heap;
public:
    void push(long long val) {
        heap.push_back(val);
        siftUp(heap.size() - 1);
    }
    void siftUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (heap[parent] <= heap[index]) break;
